def render_notice(message, kind="info"):
    """Aviso visual de color uniforme para evitar solapes de fondos en st.info/st.success."""
    kind = kind if kind in {"success", "info", "warning", "error"} else "info"
    st.markdown(
        f"<div class='het-notice notice-{kind}'>{escape(str(message))}</div>",
        unsafe_allow_html=True,
    )


def find_logo_path():
    candidates = [
        "assets/logo_elche.png",
        "assets/LOGO-HOR-CAS AZUL.png",
        "LOGO-HOR-CAS AZUL.png",
        "/mnt/data/LOGO-HOR-CAS AZUL.png",
    ]
    for p in candidates:
        if os.path.exists(p):
            return p
    return None


def get_logo_base64():
    """Devuelve el logo en base64 desde archivo local o desde respaldo embebido."""
    path = find_logo_path()
    if path:
        try:
            with open(path, "rb") as f:
                return base64.b64encode(f.read()).decode("utf-8")
        except Exception:
            pass
    return LOGO_BASE64_FALLBACK


