# =========================================================
# UTILIDADES DE CARGA Y NORMALIZACIÓN
# =========================================================
def file_to_bytes(uploaded_file):
    return uploaded_file.getvalue()


def hash_bytes(data: bytes) -> str:
    return hashlib.md5(data).hexdigest()


def normaliza_texto(texto):
    if pd.isna(texto):
        return ""
    return (
        str(texto).strip().lower()
        .replace("\n", " ")
        .replace("á", "a")
        .replace("é", "e")
        .replace("í", "i")
        .replace("ó", "o")
        .replace("ú", "u")
        .replace("ü", "u")
    )


def clean_columns(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    out.columns = [str(c).strip() for c in out.columns]
    return out.dropna(axis=1, how="all").dropna(axis=0, how="all")


def read_sheet(xls_bytes: bytes, sheet_name: str, header=0) -> pd.DataFrame:
    df = pd.read_excel(BytesIO(xls_bytes), sheet_name=sheet_name, header=header)
    return clean_columns(df)


def read_het_workbook(xls_bytes: bytes) -> dict:
    xls = pd.ExcelFile(BytesIO(xls_bytes))
    sheets = {"_sheet_names": xls.sheet_names}
    for sheet in xls.sheet_names:
        # Las hojas HET principales tienen cabecera en fila 1.
        if sheet in {
            "patrones_vector", "puestos_vector", "diccionario_columnas", "resultados_het_cd",
            "comparacion_externa", "impacto_economico", "pesos_modelo", "rangos_cd",
            "guia_escalas", "criterios_vectorizacion_cd", "criterios_grupos_funcionales", "calibracion_puestos_patron",
        }:
            sheets[sheet] = clean_columns(pd.read_excel(BytesIO(xls_bytes), sheet_name=sheet, header=0))
        elif sheet == "verbs_dictionary":
            # En la plantilla actual la cabecera útil está en header=3.
            sheets[sheet] = read_flexible_header(xls_bytes, sheet, required={"verbo_id", "verbo", "grupo_verbo", "definicion", "categoria"})
        elif sheet == "compatibility_verbs":
            sheets[sheet] = read_flexible_header(xls_bytes, sheet, required={"operacion", "mando", "tecnicos", "direccion"})
        else:
            try:
                sheets[sheet] = clean_columns(pd.read_excel(BytesIO(xls_bytes), sheet_name=sheet, header=0))
            except Exception:
                pass
    return sheets


def read_flexible_header(xls_bytes: bytes, sheet_name: str, required: set) -> pd.DataFrame:
    best = None
    for header in range(0, 6):
        try:
            df = clean_columns(pd.read_excel(BytesIO(xls_bytes), sheet_name=sheet_name, header=header))
            cols_norm = {normaliza_texto(c): c for c in df.columns}
            if required.issubset(set(cols_norm.keys())):
                # Renombrar a nombres normalizados clave conservando contenido.
                rename = {cols_norm[k]: k for k in required if k in cols_norm}
                df = df.rename(columns=rename)
                return df
            if best is None or len(set(cols_norm.keys()) & required) > len(set([normaliza_texto(c) for c in best.columns]) & required):
                best = df
        except Exception:
            continue
    return best if best is not None else pd.DataFrame()


def validate_workbook(sheets: dict) -> dict:
    names = set(sheets.get("_sheet_names", []))
    missing = sorted(REQUIRED_HET_SHEETS - names)
    warnings = []
    for opt in sorted(OPTIONAL_SHEETS):
        if opt not in names:
            warnings.append(f"Hoja opcional no encontrada: {opt}")

    detail = {"ok": not missing, "missing_required": missing, "warnings": warnings}

    if not missing:
        patrones = sheets.get("patrones_vector", pd.DataFrame())
        puestos = sheets.get("puestos_vector", pd.DataFrame())
        detail["dimension_check"] = validar_dimensiones_vectoriales(puestos, patrones)
    return detail


def get_diccionario_columnas(sheets: dict) -> pd.DataFrame:
    return sheets.get("diccionario_columnas", pd.DataFrame()).copy()


def label_for_column(diccionario: pd.DataFrame, col: str) -> str:
    if diccionario is None or diccionario.empty or "codigo_columna" not in diccionario.columns:
        return col
    row = diccionario[diccionario["codigo_columna"].astype(str).str.strip() == col]
    if row.empty:
        return col
    den = row.iloc[0].get("denominacion", col)
    return f"{col} · {den}" if str(den).strip() else col


def factor_description(diccionario: pd.DataFrame, col: str) -> str:
    if diccionario is None or diccionario.empty or "codigo_columna" not in diccionario.columns:
        return ""
    row = diccionario[diccionario["codigo_columna"].astype(str).str.strip() == col]
    if row.empty:
        return ""
    parts = []
    for field in ["escala", "observacion"]:
        val = row.iloc[0].get(field, "")
        if pd.notna(val) and str(val).strip():
            parts.append(str(val).strip())
    return " | ".join(parts)


def _norm_code(value) -> str:
    return str(value or "").strip().upper().replace(".", "_").replace(" ", "")


def get_criteria_df(sheets: dict) -> pd.DataFrame:
    df = sheets.get("criterios_vectorizacion_cd", pd.DataFrame()).copy()
    if df.empty:
        return df
    df.columns = [str(c).strip() for c in df.columns]
    if "codigo" not in df.columns:
        return pd.DataFrame()
    df["_codigo_norm"] = df["codigo"].apply(_norm_code)
    return df


def get_criterion(criteria: pd.DataFrame, codigo: str) -> dict:
    if criteria is None or criteria.empty or "_codigo_norm" not in criteria.columns:
        return {}
    row = criteria[criteria["_codigo_norm"] == _norm_code(codigo)]
    if row.empty:
        return {}
    return row.iloc[0].to_dict()


def criterion_value_text(criterion: dict, numeric_value) -> str:
    if not criterion:
        return ""
    try:
        iv = int(float(numeric_value))
    except Exception:
        return "No aplicable estructuralmente al subfactor."
    key = f"valor_{iv}"
    val = criterion.get(key, "")
    return "" if pd.isna(val) else str(val).strip()


def criterion_examples_text(criterion: dict, numeric_value=None) -> str:
    if not criterion:
        return ""
    if numeric_value is not None:
        try:
            iv = int(float(numeric_value))
            val = criterion.get(f"ejemplo_{iv}", "")
            if pd.notna(val) and str(val).strip():
                return str(val).strip()
        except Exception:
            pass
    vals = []
    for i in range(0, 4):
        v = criterion.get(f"ejemplo_{i}", "")
        if pd.notna(v) and str(v).strip():
            vals.append(f"{i}: {str(v).strip()}")
    return " | ".join(vals)


def render_criterion_box(criterion: dict):
    if not criterion:
        render_notice("No hay criterio detallado para este subfactor en la hoja `criterios_vectorizacion_cd`.", "warning")
        return
    st.markdown(f"**Pregunta de evaluación**  \n{criterion.get('pregunta_evaluacion', '')}")
    cautela = criterion.get("cautela", "")
    if pd.notna(cautela) and str(cautela).strip():
        st.markdown(f"**Cautela**  \n{cautela}")
    rows = []
    for i in range(0, 4):
        rows.append({
            "Valor": i,
            "Criterio": criterion.get(f"valor_{i}", ""),
            "Ejemplo": criterion.get(f"ejemplo_{i}", ""),
        })
    st.dataframe(pd.DataFrame(rows), use_container_width=True, hide_index=True)
    evid = criterion.get("evidencias_recomendadas", "")
    if pd.notna(evid) and str(evid).strip():
        st.caption(f"Evidencias recomendadas: {evid}")


def get_verbs_dictionary(sheets: dict) -> pd.DataFrame:
    df = sheets.get("verbs_dictionary", pd.DataFrame()).copy()
    if df.empty:
        return df
    # Quitar columnas Unnamed y filas incompletas.
    df = df[[c for c in df.columns if not str(c).lower().startswith("unnamed")]].copy()
    for c in ["verbo_id", "verbo", "grupo_verbo", "definicion", "categoria"]:
        if c not in df.columns:
            df[c] = ""
    df = df[df["verbo_id"].notna() & (df["verbo_id"].astype(str).str.strip() != "")]
    return df


def make_empty_puesto_row() -> dict:
    row = {"id_het": "NUEVO", "denominacion_normalizada": "", "grupo_subgrupo": "", "cd_vigente": None}
    for c in F_COLUMNS:
        row[c] = 0
    for c in CD_COLUMNS:
        row[c] = None
    return row


def row_from_existing(df: pd.DataFrame, idx: int) -> dict:
    return df.iloc[idx].to_dict()


def build_functional_row_from_selected(selected_verbo_ids, denominacion, grupo, cd_vigente) -> dict:
    row = make_empty_puesto_row()
    row["id_het"] = "CONFIGURADOR"
    row["denominacion_normalizada"] = denominacion
    row["grupo_subgrupo"] = grupo
    row["cd_vigente"] = cd_vigente
    selected = {str(v).strip().upper() for v in selected_verbo_ids}
    for c in F_COLUMNS:
        row[c] = 1 if c.upper() in selected else 0
    return row


def apply_factor_answers_to_row(row: dict, answers: dict) -> dict:
    out = dict(row)
    for col, val in answers.items():
        if val in {"N.A.", "No aplica", "No aplicable"}:
            out[col] = None
        else:
            try:
                out[col] = int(float(val))
            except Exception:
                out[col] = None
    return out


def parse_factor_value(value):
    if pd.isna(value) or value == "":
        return "N.A."
    try:
        iv = int(float(value))
        return str(iv) if iv in {0, 1, 2, 3} else "N.A."
    except Exception:
        return "N.A."


def render_status_pill(state: str):
    if state == "OK":
        klass = "pill-ok"
    elif state in {"FUERA_RANGO_INFERIOR", "FUERA_RANGO_SUPERIOR", "GRUPO_NO_VALIDO", "SIN_RANGO_DEFINIDO"}:
        klass = "pill-error"
    else:
        klass = "pill-warning"
    st.markdown(f"<span class='het-pill {klass}'>{escape(str(state))}</span>", unsafe_allow_html=True)

