def img_to_base64(path_imagen):
    if not path_imagen or not os.path.exists(path_imagen):
        return None
    with open(path_imagen, "rb") as f:
        return base64.b64encode(f.read()).decode("utf-8")


def html_list(items):
    if not items:
        return "<li>No se aprecian elementos destacables.</li>"
    return "".join(f"<li>{escape(str(x))}</li>" for x in items)



def factor_value_label(value):
    if value is None or value == "" or (isinstance(value, float) and pd.isna(value)):
        return "N.A."
    try:
        iv = int(float(value))
        return str(iv) if iv in {0, 1, 2, 3} else "N.A."
    except Exception:
        return str(value)


def get_selected_verb_rows(verbs: pd.DataFrame, selected_ids) -> list:
    if verbs is None or verbs.empty or not selected_ids:
        return []
    selected_set = {str(x).strip().upper() for x in selected_ids}
    df = verbs.copy()
    df["_id_norm"] = df["verbo_id"].astype(str).str.strip().str.upper()
    rows = []
    for _, r in df[df["_id_norm"].isin(selected_set)].iterrows():
        rows.append({
            "verbo_id": str(r.get("verbo_id", "")),
            "verbo": str(r.get("verbo", "")),
            "grupo_verbo": str(r.get("grupo_verbo", "")),
            "categoria": str(r.get("categoria", "")),
            "definicion": str(r.get("definicion", "")),
        })
    return rows


def get_factor_trace(diccionario: pd.DataFrame, row: dict, criteria: pd.DataFrame = None) -> list:
    trace = []
    for col in CD_COLUMNS:
        val = row.get(col, None)
        label = factor_value_label(val)
        criterion = get_criterion(criteria, col) if criteria is not None else {}
        trace.append({
            "codigo": col,
            "criterio": label_for_column(diccionario, col),
            "valor": label,
            "valor_numerico": "" if label == "N.A." else row.get(col, ""),
            "criterio_valor": criterion_value_text(criterion, val),
            "ejemplo": criterion_examples_text(criterion, val),
        })
    return trace


def get_compatibility_df(sheets: dict) -> pd.DataFrame:
    return sheets.get("compatibility_verbs", pd.DataFrame())


def normalizar_verbo_id(v) -> str:
    return str(v or "").strip().upper().replace(".", "_")


def evaluar_compatibilidad_verbos(selected_ids, compatibility_df: pd.DataFrame) -> dict:
    """Comprueba que los verbos seleccionados pertenecen a un único ámbito funcional.

    La hoja compatibility_verbs arrastra la lógica de la app original: columnas
    operacion, mando, tecnicos y direccion con 1/0 por verbo F.
    """
    ids = {normalizar_verbo_id(x) for x in (selected_ids or []) if str(x).strip()}
    levels = ["operacion", "mando", "tecnicos", "direccion"]
    if not ids or compatibility_df is None or compatibility_df.empty:
        return {"ok": True, "ambitos": [], "mensaje": "Sin selección o sin matriz de compatibilidad."}
    df = compatibility_df.copy()
    df.columns = [str(c).strip().lower() for c in df.columns]
    # La columna de código puede venir sin nombre; localizamos la primera columna que contenga F1, F2...
    code_col = None
    for c in df.columns:
        vals = df[c].astype(str).str.strip().str.upper()
        if vals.str.match(r"^F\d+$").any():
            code_col = c
            break
    if code_col is None:
        return {"ok": True, "ambitos": [], "mensaje": "No se ha podido localizar la columna de códigos de verbo en compatibility_verbs."}
    active = set()
    usados = df[df[code_col].astype(str).map(normalizar_verbo_id).isin(ids)]
    for lvl in levels:
        if lvl in usados.columns:
            vals = pd.to_numeric(usados[lvl], errors="coerce").fillna(0)
            if (vals > 0).any():
                active.add(lvl)
    nombres = {"operacion": "operación", "mando": "mando", "tecnicos": "técnicos", "direccion": "dirección"}
    ambitos = [nombres.get(x, x) for x in levels if x in active]
    ok = len(active) <= 1
    if ok:
        mensaje = "Selección compatible" + (f": ámbito {ambitos[0]}." if ambitos else ".")
    else:
        mensaje = "Selección incompatible: no deben mezclarse verbos de " + ", ".join(ambitos) + "."
    return {"ok": ok, "ambitos": ambitos, "mensaje": mensaje}


def attach_traceability(result: dict, puesto_row: dict, verbs: pd.DataFrame, selected_ids, diccionario: pd.DataFrame, criteria: pd.DataFrame = None) -> dict:
    out = dict(result)
    out["trazabilidad"] = {
        "datos_entrada": {
            "id_het": puesto_row.get("id_het", ""),
            "denominacion_normalizada": puesto_row.get("denominacion_normalizada", ""),
            "grupo_subgrupo": puesto_row.get("grupo_subgrupo", ""),
            "cd_vigente": puesto_row.get("cd_vigente", ""),
        },
        "verbos_funcionales": get_selected_verb_rows(verbs, selected_ids),
        "factores_cd": get_factor_trace(diccionario, puesto_row, criteria),
    }
    return out


def html_trace_rows(items, columns):
    if not items:
        return f"<tr><td colspan='{len(columns)}'>Sin datos trazables.</td></tr>"
    rows = []
    for item in items:
        rows.append("<tr>" + "".join(f"<td>{escape(str(item.get(col, '')))}</td>" for col in columns) + "</tr>")
    return "".join(rows)

