def select_group_and_cd(key_prefix="base", default_group="C1", default_cd=20):
    options = ["A1", "A2", "B", "C1", "C2", "AP", "E"]
    grupo_key = f"{key_prefix}_grupo"
    cd_key = f"{key_prefix}_cd"
    if grupo_key not in st.session_state:
        st.session_state[grupo_key] = default_group if default_group in options else "C1"
    if cd_key not in st.session_state:
        st.session_state[cd_key] = int(default_cd or 0)
    col1, col2 = st.columns(2)
    with col1:
        grupo = st.selectbox(
            "Grupo/Subgrupo",
            options=options,
            key=grupo_key,
        )
    with col2:
        cd = st.number_input("CD vigente / inicial", min_value=0, max_value=30, step=1, key=cd_key)
    return grupo, cd



def persistent_multiselect(label, options, persist_key, widget_key, placeholder=None):
    """Multiselect que conserva el valor aunque se cambie de módulo/página.

    Streamlit puede limpiar el estado de widgets que dejan de renderizarse al cambiar de módulo.
    Por eso se guarda una copia no vinculada al widget y se rehidrata antes de mostrarlo.
    """
    stored = st.session_state.get(persist_key, [])
    stored = [x for x in stored if x in options]
    if widget_key not in st.session_state:
        st.session_state[widget_key] = stored

    def _sync_multiselect():
        st.session_state[persist_key] = list(st.session_state.get(widget_key, []))

    selected = st.multiselect(
        label,
        options=options,
        key=widget_key,
        placeholder=placeholder,
        on_change=_sync_multiselect,
    )
    st.session_state[persist_key] = list(selected)
    return selected


def get_persistent_factor_default(base_row, col, persist_key):
    """Devuelve el valor persistido de un factor o, si no existe, el valor del puesto base."""
    factor_store = st.session_state.setdefault(persist_key, {})
    if col not in factor_store:
        factor_store[col] = parse_factor_value(base_row.get(col, None) if isinstance(base_row, dict) else None)
    return factor_store[col]


def persist_factor_value(persist_key, col, value):
    factor_store = st.session_state.setdefault(persist_key, {})
    factor_store[col] = value


def render_factor_questionnaire(diccionario: pd.DataFrame, criteria: pd.DataFrame, base_row: dict, key_prefix: str) -> dict:
    st.markdown("### Factores HET-CD")
    st.caption("Seleccione el valor que mejor describa la exigencia objetiva del puesto tipo. 0 = no concurre; 1 = básico; 2 = medio/cualificado; 3 = alto; N.A. = no aplicable estructuralmente. Ante duda, use el nivel inferior salvo evidencia suficiente.")
    answers = {}
    options = ["N.A.", "0", "1", "2", "3"]
    for factor, cols in CD_SUBFACTOR_COLUMNS.items():
        factor_name = CD_FACTOR_PREFIXES.get(factor, factor)
        with st.expander(f"{factor} · {factor_name}", expanded=False):
            for col in cols:
                label = label_for_column(diccionario, col)
                criterion = get_criterion(criteria, col)
                help_txt = factor_description(diccionario, col)
                if criterion:
                    pregunta = criterion.get("pregunta_evaluacion", "")
                    if pd.notna(pregunta) and str(pregunta).strip():
                        st.markdown(f"**{col} · {criterion.get('subvariable', label).strip() if isinstance(criterion.get('subvariable', ''), str) else label}**")
                        st.caption(str(pregunta))
                persist_key = f"{key_prefix}_persist"
                default = get_persistent_factor_default(base_row, col, persist_key)
                value = st.radio(
                    label if not criterion else "Valoración",
                    options=options,
                    index=options.index(default) if default in options else 0,
                    horizontal=True,
                    key=f"{key_prefix}_{col}",
                    help=help_txt or None,
                )
                persist_factor_value(persist_key, col, value)
                answers[col] = value
                selected_criterion = criterion_value_text(criterion, value)
                if selected_criterion and value != "N.A.":
                    st.caption(f"Criterio seleccionado: {selected_criterion}")
                with st.expander(f"Ver criterio de valoración de {col}", expanded=False):
                    render_criterion_box(criterion)
                st.markdown("---")
    return answers



def _fmt_score(value):
    try:
        return f"{float(value):.4f}"
    except Exception:
        return str(value or "")


def _interpret_score(value):
    try:
        v = float(value)
    except Exception:
        return "sin interpretación"
    if v >= 0.90:
        return "coincidencia muy alta"
    if v >= 0.85:
        return "coincidencia alta"
    if v >= 0.80:
        return "coincidencia media-alta"
    if v >= 0.70:
        return "coincidencia media"
    return "coincidencia débil o insuficiente"


def render_cd_explanation(result: dict):
    """Explica de forma legible cómo se obtiene la recomendación de CD."""
    top = result.get("top_k_patrones", []) or []
    sims = result.get("similitudes", {}) or {}
    res = result.get("resultado_cd", {}) or {}
    val = result.get("validacion_rango", {}) or {}
    if not top:
        render_notice("No hay patrones de referencia suficientes para explicar la recomendación.", "warning")
        return

    k1 = top[0]
    k1_cd = k1.get("cd_referencia")
    cd_rec = res.get("cd_tecnico_recomendado")
    cd_adj = res.get("cd_tecnico_ajustado")
    cd_cont = res.get("cd_continuo")
    sim_f = k1.get("similitud_funcional", sims.get("funcional"))
    sim_cd = k1.get("similitud_cd", sims.get("factores_cd"))
    sim_total = k1.get("similitud_total", sims.get("combinada"))

    st.markdown("### Cómo se ha obtenido el CD")
    st.markdown(
        f"""
        <div class="het-card">
        <p>El motor compara el puesto evaluado con los patrones ampliados de referencia y ordena los resultados por similitud combinada HET-CD.</p>
        <p>Primero identifica el patrón K1, que es el más parecido. En este caso, el K1 es {escape(str(k1.get('patron_id','')))}, con CD de referencia {escape(str(k1_cd))}.</p>
        <p>Después aplica el rango legal del grupo/subgrupo. Por eso hay dos datos distintos: <strong>CD K1 orientativo</strong> y <strong>CD final ajustado a rango</strong>.</p>
        <p>Fórmula de similitud total: 40 % verbos funcionales + 60 % factores HET-CD.</p>
        </div>
        """,
        unsafe_allow_html=True,
    )
    c1, c2, c3 = st.columns(3)
    c1.metric("Similitud funcional K1", _fmt_score(sim_f), help="Coincidencia en el vector F1-F49 de verbos funcionales.")
    c2.metric("Similitud factores CD K1", _fmt_score(sim_cd), help="Coincidencia en CD1-CD6: especialización, responsabilidad, competencia, mando y complejidad.")
    c3.metric("Similitud combinada K1", _fmt_score(sim_total), help="0,40 × funcional + 0,60 × factores CD.")
    st.caption(f"Lectura del coeficiente total: {_interpret_score(sim_total)}. Un valor próximo a 1 indica mucha proximidad al patrón; un valor bajo exige cautela o revisión de la vectorización.")

    if cd_cont is not None:
        st.markdown(
            f"El <strong>CD continuo Top-K</strong> es <strong>{escape(str(cd_cont))}</strong>. Se muestra solo como indicador de tendencia entre los patrones más próximos; no sustituye al K1.",
            unsafe_allow_html=True,
        )

    if str(cd_rec) != str(cd_adj):
        render_notice(
            f"El patrón K1 sitúa el puesto en CD {cd_rec}, pero el CD final se limita a CD {cd_adj} por el rango legal configurado para el grupo/subgrupo "
            f"({val.get('cd_min')} - {val.get('cd_max')})."
        , "warning")
    else:
        render_notice(f"El CD K1 orientativo ({cd_rec}) coincide con el CD final tras aplicar el rango legal configurado.", "success")


def render_impacto_economico(result: dict):
    """Módulo visible de impacto económico y riesgos asociados."""
    ident = result.get("identificacion", {}) or {}
    res = result.get("resultado_cd", {}) or {}
    arr = result.get("efecto_arrastre", {}) or {}
    diferencial = res.get("diferencial_cd")
    try:
        diferencial_num = int(diferencial)
    except Exception:
        diferencial_num = None

    st.markdown("### Impacto económico y riesgos")
    riesgo = arr.get("riesgo_arrastre", "NO_CALCULADO")
    st.write(f"**Riesgo de arrastre:** {riesgo}")
    st.caption(arr.get("observacion", ""))

    if diferencial_num is None:
        render_notice("No puede calcularse impacto económico porque no hay diferencial de CD calculado.", "info")
        return
    if diferencial_num <= 0:
        render_notice("No se activa impacto económico estimado porque no hay propuesta de aumento de CD.", "info")
        result["impacto_economico_estimado"] = {
            "aplica": False,
            "motivo": "No hay diferencial positivo de CD.",
        }
        return

    key_base = str(ident.get("id_het") or ident.get("denominacion_normalizada") or "caso").replace(" ", "_")
    with st.expander("Calcular impacto económico estimado", expanded=False):
        st.caption("Este cálculo es posterior al resultado técnico. No condiciona la recomendación de CD; solo estima coste potencial si se tramitara una subida.")
        col1, col2, col3 = st.columns(3)
        dotaciones = col1.number_input("Dotaciones afectadas", min_value=0, value=int(st.session_state.get(f"imp_dot_{key_base}", 1)), step=1, key=f"imp_dot_{key_base}")
        coste_unitario = col2.number_input("Coste anual por punto/dotación (€)", min_value=0.0, value=float(st.session_state.get(f"imp_coste_{key_base}", 0.0)), step=100.0, key=f"imp_coste_{key_base}")
        meses = col3.number_input("Meses de efecto", min_value=1, max_value=12, value=int(st.session_state.get(f"imp_meses_{key_base}", 12)), step=1, key=f"imp_meses_{key_base}")
        coste_total = diferencial_num * dotaciones * coste_unitario * (meses / 12.0)
        st.metric("Coste total estimado", f"{coste_total:,.2f} €".replace(",", "X").replace(".", ",").replace("X", "."))
        result["impacto_economico_estimado"] = {
            "aplica": True,
            "diferencial_cd": diferencial_num,
            "dotaciones_afectadas": int(dotaciones),
            "coste_unitario_anual": float(coste_unitario),
            "meses_efecto": int(meses),
            "coste_total_estimado": round(float(coste_total), 2),
            "observacion": "Estimación orientativa posterior al resultado técnico; requiere memoria económica formal si se tramita modificación de RPT.",
        }

def _pretty_resultado_preliminar(code: str) -> tuple[str, str]:
    code = str(code or "SIN_DATOS")
    mapping = {
        "MANTENER": ("Mantener nivel", "El CD final ajustado coincide con el CD vigente."),
        "ANALIZAR_AL_ALZA": ("Analizar al alza", "El modelo aprecia un diferencial positivo respecto del CD vigente."),
        "ANALIZAR_A_LA_BAJA": ("Analizar a la baja", "El modelo aprecia un diferencial negativo respecto del CD vigente."),
        "INCIDENCIA_NORMATIVA": ("Incidencia normativa", "El CD vigente o el CD técnico requiere contraste con el rango legal configurado."),
        "REVISION_AGRUPADA": ("Revisión agrupada", "Existen comparables internos que aconsejan revisar el caso junto con puestos análogos."),
        "SIN_DATOS_SUFICIENTES": ("Sin datos suficientes", "No hay información bastante para emitir una orientación técnica estable."),
        "SIN_DATOS": ("Sin datos", "No se ha calculado todavía un resultado preliminar."),
    }
    return mapping.get(code, (code.replace("_", " ").capitalize(), "Resultado preliminar del modelo HET-CD."))


def render_preliminar_card(code: str, res: dict):
    title, sub = _pretty_resultado_preliminar(code)
    cd_k1 = res.get("cd_tecnico_recomendado", "")
    cd_final = res.get("cd_tecnico_ajustado", "")
    extra = f"CD K1 orientativo: {cd_k1} · CD final ajustado a rango: {cd_final}"
    st.markdown(
        f"""
        <div class="preliminar-card">
          <div class="preliminar-label">Resultado preliminar</div>
          <div class="preliminar-title">{title}</div>
          <div class="preliminar-sub">{sub}</div>
          <div class="preliminar-sub">{extra}</div>
        </div>
        """,
        unsafe_allow_html=True,
    )


def render_result(result: dict):
    ident = result.get("identificacion", {})
    val = result.get("validacion_rango", {})
    res = result.get("resultado_cd", {})
    sims = result.get("similitudes", {})
    arr = result.get("efecto_arrastre", {})

    st.markdown("## Resultado HET-CD")
    col1, col2, col3, col4 = st.columns(4)
    col1.metric("CD vigente", ident.get("cd_vigente"))
    col2.metric("CD K1 orientativo", res.get("cd_tecnico_recomendado"))
    col3.metric("CD final rango", res.get("cd_tecnico_ajustado"))
    col4.metric("Diferencial", res.get("diferencial_cd"))

    if str(res.get("cd_tecnico_recomendado")) != str(res.get("cd_tecnico_ajustado")):
        render_notice(
            f"El patrón más similar indica CD {res.get('cd_tecnico_recomendado')}, pero el resultado final mostrado para efectos de propuesta queda en CD {res.get('cd_tecnico_ajustado')} por aplicación del rango legal del grupo/subgrupo."
        , "warning")

    metodo = res.get("metodo_recomendacion", "")
    cd_cont = res.get("cd_continuo", None)
    if metodo:
        st.caption(
            "Criterio de cálculo: el CD K1 orientativo se toma del patrón K1 más similar; el CD final puede quedar limitado por el rango legal. "
            "El CD continuo Top-K se conserva como indicador auxiliar de tendencia o zona límite."
        )
    if cd_cont is not None:
        try:
            cd_top1 = float(res.get("cd_tecnico_recomendado"))
            tendencia = "al alza" if float(cd_cont) > cd_top1 else ("a la baja" if float(cd_cont) < cd_top1 else "neutra")
        except Exception:
            tendencia = "no calculada"
        st.write(f"**CD continuo Top-K:** {cd_cont} · **Tendencia auxiliar:** {tendencia}")

    render_cd_explanation(result)

    st.markdown("### Validación normativa inicial")
    render_status_pill(val.get("estado", "SIN_ESTADO"))
    st.write(val.get("mensaje", ""))

    st.markdown("### Similitudes")
    scol1, scol2, scol3 = st.columns(3)
    scol1.metric("Funcional", sims.get("funcional"))
    scol2.metric("Factores CD", sims.get("factores_cd"))
    scol3.metric("Combinada", sims.get("combinada"))

    render_preliminar_card(res.get("resultado_preliminar", "SIN_DATOS"), res)

    st.markdown("### Patrones de referencia próximos")
    top_df = pd.DataFrame(result.get("top_k_patrones", []))
    if not top_df.empty:
        st.dataframe(top_df, use_container_width=True, hide_index=True)
    else:
        render_notice("No se han obtenido patrones de referencia.", "warning")

    st.markdown("### Comparables internos / efecto arrastre")
    st.write(f"**Riesgo:** {arr.get('riesgo_arrastre')}")
    st.caption(arr.get("observacion", ""))
    comp_df = pd.DataFrame(result.get("comparables_internos", []))
    if not comp_df.empty:
        st.dataframe(comp_df, use_container_width=True, hide_index=True)
    else:
        render_notice("No hay comparables internos disponibles. En la plantilla actual `puestos_vector` está vacía, por lo que no se puede calcular arrastre real hasta cargar puestos existentes.", "info")

    render_impacto_economico(result)

    st.markdown("### Explicación")
    exp = result.get("explicacion", {})
    st.write(exp.get("resumen", ""))
    for m in exp.get("motivos", []):
        st.write(f"• {m}")
    traz = result.get("trazabilidad", {})
    if traz:
        with st.expander("Trazabilidad de datos de entrada", expanded=False):
            verb_df = pd.DataFrame(traz.get("verbos_funcionales", []))
            fact_df = pd.DataFrame(traz.get("factores_cd", []))
            if not verb_df.empty:
                st.markdown("**Verbos funcionales seleccionados**")
                st.dataframe(verb_df, use_container_width=True, hide_index=True)
            if not fact_df.empty:
                st.markdown("**Factores HET-CD seleccionados**")
                st.dataframe(fact_df, use_container_width=True, hide_index=True)

    if result.get("advertencias"):
        with st.expander("Advertencias técnicas y jurídicas"):
            for w in result.get("advertencias", []):
                st.write(f"• {w}")


