def build_individual_reports_zip(analysis: dict, config_name: str, sheets: dict = None) -> bytes:
    """Genera un ZIP con informes HTML individuales para todos los resultados.

    Además de propagar importes recalculados con dotaciones, reconstruye la
    trazabilidad desde puestos_vector para que los informes de análisis masivo no
    aparezcan con verbos/factores en blanco.
    """
    import zipfile
    resumen_map = {}
    try:
        for row in analysis.get("resumen_rows", []) or []:
            resumen_map[str(row.get("id_het"))] = row
    except Exception:
        resumen_map = {}

    puesto_map = {}
    verbs = pd.DataFrame(); dic = pd.DataFrame(); criteria = pd.DataFrame()
    if sheets:
        puestos = sheets.get("puestos_vector", pd.DataFrame())
        if isinstance(puestos, pd.DataFrame) and not puestos.empty and "id_het" in puestos.columns:
            for _, rr in puestos.iterrows():
                puesto_map[str(rr.get("id_het"))] = rr.to_dict()
        verbs = get_verbs_dictionary(sheets)
        dic = get_diccionario_columnas(sheets)
        criteria = get_criteria_df(sheets)

    output = BytesIO()
    with zipfile.ZipFile(output, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        for idx, result in enumerate(analysis.get("resultados", []) or [], start=1):
            ident = result.get("identificacion", {}) or {}
            patched = dict(result)
            key = str(ident.get("id_het"))
            if key in resumen_map:
                row = resumen_map[key]
                impacto = dict(patched.get("impacto_economico_auto", {}) or {})
                for src, dst in [
                    ("diferencial_anual_por_dotacion", "diferencial_anual_por_dotacion"),
                    ("dotaciones", "dotaciones"),
                    ("impacto_anual_total", "impacto_anual_total"),
                    ("impacto_periodo", "impacto_periodo"),
                ]:
                    if src in row:
                        impacto[dst] = row.get(src)
                if "observacion_impacto" in row:
                    impacto["motivo"] = row.get("observacion_impacto")
                patched["impacto_economico_auto"] = impacto
            if key in puesto_map:
                puesto_row = puesto_map[key]
                selected_ids = []
                for c in F_COLUMNS:
                    try:
                        if int(float(puesto_row.get(c, 0) or 0)) == 1:
                            selected_ids.append(c)
                    except Exception:
                        pass
                patched = attach_traceability(patched, puesto_row, verbs, selected_ids, dic, criteria)
            raw_name = str(ident.get("denominacion_normalizada") or ident.get("id_het") or f"puesto_{idx}")
            safe = "".join(ch if ch.isalnum() or ch in "-_" else "_" for ch in raw_name)[:80]
            html = build_html_report(patched, config_name)
            zf.writestr(f"{idx:03d}_{safe}.html", html)
    return output.getvalue()

