def _load_config_from_bytes(bytes_: bytes, name: str) -> None:
    h = hash_bytes(bytes_)
    if st.session_state.get("config_hash") != h:
        sheets = read_het_workbook(bytes_)
        validation = validate_workbook(sheets)
        st.session_state.het_sheets = sheets
        st.session_state.config_hash = h
        st.session_state.config_name = name
        st.session_state.config_size_kb = round(len(bytes_) / 1024, 1)
        st.session_state.validation = validation
        st.session_state.last_result = None

